export const JEOLGI_EVENT_COUNT = EVENTS.length;
export const JEOLGI_RANGE_LOW_YEAR = 1919;
export const JEOLGI_RANGE_HIGH_YEAR = 2031;

/** 출생 UTC ms → { month_branch, sajuYear }. binary search 기반. */
export function resolveMonthYear(birthUtcMs: number): { branch: number; sajuYear: number } {
  if (birthUtcMs < EVENTS[0][0]) {
    // 범위 이전: 첫 event의 year-1, branch는 0(子)으로 가정 (대설 이후 자월)
    return { branch: 0, sajuYear: EVENTS[0][2] - 1 };
  }
  const last = EVENTS[EVENTS.length - 1];
  if (birthUtcMs >= last[0]) {
    return { branch: last[1], sajuYear: last[2] };
  }
  let lo = 0, hi = EVENTS.length - 1;
  while (lo < hi) {
    const mid = (lo + hi + 1) >>> 1;
    if (EVENTS[mid][0] <= birthUtcMs) lo = mid;
    else hi = mid - 1;
  }
  const ev = EVENTS[lo];
  return { branch: ev[1], sajuYear: ev[2] };
}
